params.rule_content:
# H2 - SQLi attempt from internal host to DVWA
# IoC: src_ip 10.20.30.202, dest_ip 10.20.32.80, URL contains 'UNION SELECT'
alert http $HOME_NET any -> $EXTERNAL_NET $HTTP_PORTS (msg:"H2_SQLI_DVWA_UNION_SELECT"; flow:to_server,established; content:"/\?id="; http_uri; nocase; pcre:"/UNION[ \t]+SELECT/i"; sid:2000001; rev:1; classtype:web-application-attack; reference:url,example.com/h2);
